{"content": "const { app, BrowserView, BrowserWindow, session } = require('electron');

const STREAM_URL = process.argv[2] || 'http://localhost:9988/stream';

app.disableHardwareAcceleration();
app.commandLine.appendSwitch('disable-gpu');
app.commandLine.appendSwitch('disable-software-rasterizer');
app.commandLine.appendSwitch('no-sandbox');
app.commandLine.appendSwitch('disable-dev-shm-usage');
app.commandLine.appendSwitch('disable-gpu-compositing');

let mainWindow;

function createWindow() {
  mainWindow = new BrowserWindow({
    width: 640,
    height: 576,
    title: 'Pokemon Stream',
    backgroundColor: '#000000',
    webPreferences: {
      nodeIntegration: false,
      contextIsolation: true,
      webSecurity: true,
    }
  });

  // Load the stream directly
  mainWindow.loadURL(STREAM_URL).catch(err => {
    console.error('Failed to load stream:', err.message);
    process.exit(1);
  });

  mainWindow.on('closed', () => {
    app.quit();
  });
}

app.whenReady().then(createWindow);
app.on('window-all-closed', () => app.quit());
app.on('activate', () => {
  if (BrowserWindow.getAllWindows().length === 0) createWindow();
});", "path": "/home/Evan/pokemon-stream/main.js"}

